// SRS Anki-style spaced repetition system (simplified SM-2)
// State persisted in localStorage under key "hifz.srs.v1"

const STORAGE_KEY = "hifz.srs.v1";

// Default intervals in days for each repetition level
const INTERVALS_DAYS = [1, 3, 7, 14, 30, 90, 180];

function nowIso() {
  return new Date().toISOString();
}

function addDays(iso, days) {
  const d = new Date(iso);
  d.setDate(d.getDate() + days);
  return d.toISOString();
}

export function loadAll() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    return JSON.parse(raw);
  } catch {
    return {};
  }
}

function saveAll(data) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}

export function verseKey(surah, ayah) {
  return `${surah}:${ayah}`;
}

export function getCard(surah, ayah) {
  const all = loadAll();
  return all[verseKey(surah, ayah)] || null;
}

/**
 * Mark a verse as "Maîtrisé" — adds it to SRS (level 0) or advances it
 * to the next interval if already present.
 */
export function markMastered(surah, ayah, surahName) {
  const all = loadAll();
  const key = verseKey(surah, ayah);
  const existing = all[key];

  const level = existing ? Math.min(existing.level + 1, INTERVALS_DAYS.length - 1) : 0;
  const days = INTERVALS_DAYS[level];
  const now = nowIso();

  all[key] = {
    surah,
    ayah,
    surahName: surahName || existing?.surahName || "",
    level,
    createdAt: existing?.createdAt || now,
    lastReviewedAt: now,
    nextReviewAt: addDays(now, days),
    timesReviewed: (existing?.timesReviewed || 0) + 1,
  };
  saveAll(all);
  return all[key];
}

/** Lower the level (failed review). */
export function resetCard(surah, ayah) {
  const all = loadAll();
  const key = verseKey(surah, ayah);
  const existing = all[key];
  if (!existing) return null;
  const now = nowIso();
  all[key] = {
    ...existing,
    level: 0,
    lastReviewedAt: now,
    nextReviewAt: addDays(now, INTERVALS_DAYS[0]),
  };
  saveAll(all);
  return all[key];
}

export function removeCard(surah, ayah) {
  const all = loadAll();
  delete all[verseKey(surah, ayah)];
  saveAll(all);
}

export function getDueCards() {
  const all = loadAll();
  const now = new Date();
  return Object.values(all)
    .filter((c) => new Date(c.nextReviewAt) <= now)
    .sort((a, b) => new Date(a.nextReviewAt) - new Date(b.nextReviewAt));
}

export function getStats() {
  const all = Object.values(loadAll());
  const now = new Date();
  const due = all.filter((c) => new Date(c.nextReviewAt) <= now).length;
  const mastered = all.filter((c) => c.level >= 4).length;
  const totalReviews = all.reduce((sum, c) => sum + (c.timesReviewed || 0), 0);
  return {
    total: all.length,
    due,
    mastered,
    learning: all.length - mastered,
    totalReviews,
  };
}

export const SRS_LEVELS = INTERVALS_DAYS.length;
