import React from "react";
import { Bell, X } from "lucide-react";

/**
 * Slim banner shown at the top of Home when there are SRS cards due today.
 * Dismissible per-day via localStorage in parent.
 */
export function ReviewBanner({ dueCount, onOpenReview, onDismiss }) {
  if (dueCount <= 0) return null;
  return (
    <div
      data-testid="review-banner"
      className="w-full rounded-2xl border border-amber-500/30 bg-amber-500/[0.06] px-4 py-3 flex items-center gap-3"
    >
      <div className="w-9 h-9 rounded-full bg-amber-500/15 border border-amber-500/30 flex items-center justify-center shrink-0">
        <Bell className="w-4 h-4 text-amber-400" />
      </div>
      <div className="flex-1 min-w-0">
        <div className="text-sm font-semibold text-amber-300 leading-tight">
          {dueCount} verset{dueCount > 1 ? "s" : ""} à réviser aujourd&apos;hui
        </div>
        <button
          type="button"
          onClick={onOpenReview}
          data-testid="banner-open-review-btn"
          className="text-[11px] text-amber-400/80 hover:text-amber-300 underline-offset-2 hover:underline"
        >
          Ouvrir la révision →
        </button>
      </div>
      <button
        type="button"
        onClick={onDismiss}
        data-testid="banner-dismiss-btn"
        className="w-7 h-7 rounded-full text-slate-500 hover:text-slate-300 flex items-center justify-center"
        aria-label="Masquer"
      >
        <X className="w-4 h-4" />
      </button>
    </div>
  );
}
