import React from "react";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "./ui/sheet";
import { CalendarClock, CheckCircle2, RotateCcw, Trash2 } from "lucide-react";
import { getDueCards, loadAll, markMastered, resetCard, removeCard } from "../lib/srs";
import { SURAHS } from "../data/surahs";

export function ReviewSheet({ onJumpTo, refreshKey, onChanged }) {
  const due = getDueCards();
  const all = Object.values(loadAll());
  // refreshKey used to re-render after external changes
  void refreshKey;

  const handleReviewed = (card) => {
    const s = SURAHS.find((x) => x.number === card.surah);
    markMastered(card.surah, card.ayah, s?.name || "");
    onChanged?.();
  };

  const handleReset = (card) => {
    resetCard(card.surah, card.ayah);
    onChanged?.();
  };

  const handleRemove = (card) => {
    removeCard(card.surah, card.ayah);
    onChanged?.();
  };

  return (
    <Sheet>
      <SheetTrigger asChild>
        <button
          type="button"
          data-testid="open-review-btn"
          className="relative flex items-center gap-2 px-3 py-2 rounded-full bg-slate-900/70 border border-slate-800 text-slate-300 hover:border-emerald-500/40 transition-all text-sm"
        >
          <CalendarClock className="w-4 h-4" />
          Révision
          {due.length > 0 && (
            <span
              data-testid="due-badge"
              className="ml-1 min-w-[20px] h-5 px-1.5 rounded-full bg-emerald-500 text-slate-950 text-[11px] font-bold flex items-center justify-center"
            >
              {due.length}
            </span>
          )}
        </button>
      </SheetTrigger>
      <SheetContent
        side="bottom"
        className="bg-slate-950 border-slate-800 text-slate-100 max-h-[85vh] overflow-y-auto rounded-t-3xl"
        data-testid="review-sheet"
      >
        <SheetHeader>
          <SheetTitle className="text-slate-100 text-left">
            Calendrier de révision
          </SheetTitle>
          <SheetDescription className="text-slate-500 text-left text-xs">
            Versets à réviser maintenant et historique complet de mémorisation.
          </SheetDescription>
        </SheetHeader>

        <div className="mt-4 flex flex-col gap-4">
          <section>
            <h3 className="text-xs uppercase tracking-widest text-emerald-400 mb-3">
              À réviser maintenant ({due.length})
            </h3>
            {due.length === 0 && (
              <p className="text-sm text-slate-500 italic">
                Rien à réviser pour le moment. Reviens plus tard, qu&apos;Allah te facilite.
              </p>
            )}
            <div className="flex flex-col gap-2">
              {due.map((c) => (
                <ReviewCard
                  key={`${c.surah}:${c.ayah}`}
                  card={c}
                  onReviewed={handleReviewed}
                  onReset={handleReset}
                  onRemove={handleRemove}
                  onJumpTo={onJumpTo}
                />
              ))}
            </div>
          </section>

          {all.length > 0 && (
            <section>
              <h3 className="text-xs uppercase tracking-widest text-slate-500 mb-3 mt-4">
                Tous les versets suivis ({all.length})
              </h3>
              <div className="flex flex-col gap-2">
                {all
                  .filter((c) => !due.find((d) => d.surah === c.surah && d.ayah === c.ayah))
                  .sort((a, b) => new Date(a.nextReviewAt) - new Date(b.nextReviewAt))
                  .map((c) => (
                    <ReviewCard
                      key={`${c.surah}:${c.ayah}`}
                      card={c}
                      onReviewed={handleReviewed}
                      onReset={handleReset}
                      onRemove={handleRemove}
                      onJumpTo={onJumpTo}
                      muted
                    />
                  ))}
              </div>
            </section>
          )}
        </div>
      </SheetContent>
    </Sheet>
  );
}

function ReviewCard({ card, onReviewed, onReset, onRemove, onJumpTo, muted }) {
  const s = SURAHS.find((x) => x.number === card.surah);
  const next = new Date(card.nextReviewAt);
  const now = new Date();
  const overdue = next <= now;
  const diffMs = next - now;
  const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24));
  const label = overdue
    ? "Dû"
    : diffDays <= 0
    ? "Aujourd'hui"
    : diffDays === 1
    ? "Demain"
    : `Dans ${diffDays}j`;

  return (
    <div
      data-testid={`review-card-${card.surah}-${card.ayah}`}
      className={[
        "rounded-2xl border p-3 flex flex-col gap-3",
        muted
          ? "bg-slate-900/40 border-slate-800/60"
          : "bg-slate-900/70 border-emerald-500/20",
      ].join(" ")}
    >
      <button
        type="button"
        onClick={() => onJumpTo?.(card.surah, card.ayah)}
        className="text-left"
        data-testid={`jump-to-${card.surah}-${card.ayah}-btn`}
      >
        <div className="flex items-baseline justify-between gap-2">
          <span className="text-sm font-semibold text-slate-100">
            {s?.name || `Sourate ${card.surah}`}, V. {card.ayah}
          </span>
          <span
            className={[
              "text-[11px] uppercase tracking-widest",
              overdue ? "text-emerald-400" : "text-slate-500",
            ].join(" ")}
          >
            {label}
          </span>
        </div>
        <div className="text-[11px] text-slate-500 mt-0.5">
          Niveau {card.level + 1} • {card.timesReviewed} révision(s)
        </div>
      </button>

      <div className="flex gap-2">
        <button
          type="button"
          onClick={() => onReviewed(card)}
          data-testid={`mark-reviewed-${card.surah}-${card.ayah}-btn`}
          className="flex-1 h-9 rounded-xl bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 text-xs font-semibold flex items-center justify-center gap-1 hover:bg-emerald-500/20 transition-all"
        >
          <CheckCircle2 className="w-4 h-4" />
          Révisé
        </button>
        <button
          type="button"
          onClick={() => onReset(card)}
          data-testid={`reset-${card.surah}-${card.ayah}-btn`}
          className="h-9 px-3 rounded-xl bg-amber-500/10 border border-amber-500/30 text-amber-300 text-xs font-semibold flex items-center gap-1 hover:bg-amber-500/20 transition-all"
        >
          <RotateCcw className="w-3.5 h-3.5" />
        </button>
        <button
          type="button"
          onClick={() => onRemove(card)}
          data-testid={`remove-${card.surah}-${card.ayah}-btn`}
          className="h-9 px-3 rounded-xl bg-slate-800/70 border border-slate-700 text-slate-400 text-xs flex items-center gap-1 hover:text-rose-300 transition-all"
        >
          <Trash2 className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  );
}
