import React, { useEffect, useState } from "react";
import { ChevronLeft, ChevronRight, Loader2, Play, Pause } from "lucide-react";
import { fetchPage } from "../lib/quranApi";

const MAX_PAGE = 604;

/**
 * Mushaf-style page view: shows every ayah of the selected page (1..604).
 * Tapping an ayah focuses it as the "active" verse for the global audio
 * console + SRS controls (handled by Home.jsx).
 */
export function MushafView({
  page,
  onPageChange,
  reciter,
  activeSurah,
  activeAyah,
  onSelectAyah,
  isPlaying,
  currentPlay,
  totalLoops,
  onTogglePlay,
}) {
  const [pageData, setPageData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [pageInput, setPageInput] = useState(String(page));

  useEffect(() => {
    setPageInput(String(page));
  }, [page]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    fetchPage(page, reciter)
      .then((data) => {
        if (cancelled) return;
        setPageData(data);
      })
      .catch((err) => {
        if (cancelled) return;
        console.error(err);
        setError("Impossible de charger cette page.");
      })
      .finally(() => !cancelled && setLoading(false));
    return () => {
      cancelled = true;
    };
  }, [page, reciter]);

  const handlePageSubmit = (e) => {
    e.preventDefault();
    const n = parseInt(pageInput, 10);
    if (!Number.isNaN(n) && n >= 1 && n <= MAX_PAGE) onPageChange(n);
    else setPageInput(String(page));
  };

  const canPrev = page > 1;
  const canNext = page < MAX_PAGE;

  return (
    <div className="w-full flex flex-col gap-3" data-testid="mushaf-view">
      {/* Page navigator */}
      <div
        className="flex items-center justify-between gap-2 rounded-2xl bg-slate-900/70 border border-slate-800 p-2"
        data-testid="mushaf-navigator"
      >
        <button
          type="button"
          data-testid="mushaf-prev-page-btn"
          disabled={!canPrev}
          onClick={() => onPageChange(page - 1)}
          className="w-10 h-10 rounded-xl bg-slate-800/70 border border-slate-700 flex items-center justify-center text-slate-300 hover:border-slate-600 disabled:opacity-30 disabled:cursor-not-allowed transition-all"
          aria-label="Page précédente"
        >
          <ChevronLeft className="w-4 h-4" />
        </button>

        <form
          onSubmit={handlePageSubmit}
          className="flex-1 flex items-center justify-center gap-2"
        >
          <span className="text-[11px] uppercase tracking-[0.25em] text-slate-500">
            Page
          </span>
          <input
            type="text"
            inputMode="numeric"
            pattern="[0-9]*"
            value={pageInput}
            onChange={(e) => setPageInput(e.target.value.replace(/[^0-9]/g, ""))}
            onBlur={handlePageSubmit}
            data-testid="mushaf-page-input"
            className="w-14 h-8 text-center bg-slate-950 border border-slate-700 rounded-lg text-emerald-300 font-semibold focus:outline-none focus:border-emerald-500/60"
          />
          <span className="text-[11px] text-slate-500">/ {MAX_PAGE}</span>
        </form>

        <button
          type="button"
          data-testid="mushaf-next-page-btn"
          disabled={!canNext}
          onClick={() => onPageChange(page + 1)}
          className="w-10 h-10 rounded-xl bg-slate-800/70 border border-slate-700 flex items-center justify-center text-slate-300 hover:border-slate-600 disabled:opacity-30 disabled:cursor-not-allowed transition-all"
          aria-label="Page suivante"
        >
          <ChevronRight className="w-4 h-4" />
        </button>
      </div>

      {/* Page content */}
      <div
        className="rounded-3xl border border-slate-800/50 bg-slate-900/40 backdrop-blur-xl p-4 min-h-[300px]"
        data-testid="mushaf-page-content"
      >
        {loading && (
          <div
            className="flex items-center justify-center min-h-[200px]"
            data-testid="mushaf-loading"
          >
            <Loader2 className="w-6 h-6 text-emerald-500/70 animate-spin" />
          </div>
        )}
        {error && !loading && (
          <p className="text-sm text-rose-300 text-center py-10" data-testid="mushaf-error">
            {error}
          </p>
        )}
        {!loading && !error && pageData && (
          <div className="flex flex-col gap-3">
            {pageData.ayahs.map((a) => {
              const isActive = a.surah === activeSurah && a.ayah === activeAyah;
              const playing = isActive && isPlaying;
              return (
                <button
                  type="button"
                  key={`${a.surah}-${a.ayah}`}
                  data-testid={`mushaf-ayah-${a.surah}-${a.ayah}`}
                  onClick={() => onSelectAyah(a.surah, a.ayah)}
                  className={[
                    "w-full text-left rounded-2xl border p-3 transition-all duration-300",
                    isActive
                      ? "bg-emerald-500/8 border-emerald-500/40"
                      : "bg-slate-950/40 border-slate-800/50 hover:border-slate-700",
                    playing
                      ? "shadow-[0_0_30px_rgba(16,185,129,0.15)]"
                      : "",
                  ].join(" ")}
                >
                  <div className="flex items-baseline justify-between gap-2 mb-2">
                    <span className="text-[11px] uppercase tracking-[0.2em] text-slate-500">
                      {a.surahName} · V. {a.ayah}
                    </span>
                    {isActive && (
                      <span
                        className="inline-flex items-center gap-1 text-[10px] text-emerald-400 uppercase tracking-widest"
                        onClick={(e) => {
                          e.stopPropagation();
                          onTogglePlay?.();
                        }}
                        role="button"
                      >
                        {playing ? (
                          <>
                            <Pause className="w-3 h-3" />
                            {totalLoops > 0
                              ? `${currentPlay + 1}/${totalLoops}`
                              : "boucle"}
                          </>
                        ) : (
                          <>
                            <Play className="w-3 h-3" />
                            actif
                          </>
                        )}
                      </span>
                    )}
                  </div>
                  <p
                    dir="rtl"
                    lang="ar"
                    style={{ fontFamily: "'Amiri', serif", lineHeight: 2 }}
                    className="text-xl sm:text-2xl text-slate-100 mb-1.5"
                  >
                    {a.arabic}
                  </p>
                  {a.french && (
                    <p className="text-xs text-slate-400 italic leading-relaxed">
                      « {a.french} »
                    </p>
                  )}
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
