import React from "react";
import { Flame, CheckCircle2, ArrowRight } from "lucide-react";
import {
  getDailyChallenge,
  isChallengeDoneToday,
  getChallengeStreak,
} from "../lib/dailyChallenge";

/**
 * Compact "Défi du jour" card. Shows a deterministic verse from Juz Amma
 * (sourates 78-114) that rotates every calendar day, with a one-tap action
 * to jump to it in Verset mode.
 *
 * Read-only widget: state (done flag, streak) is recomputed from localStorage
 * every render via `refreshKey` from the parent.
 */
export function DailyChallengeCard({ onPractice, refreshKey }) {
  const challenge = getDailyChallenge();
  const done = isChallengeDoneToday();
  const streak = getChallengeStreak();
  void refreshKey;

  return (
    <div
      data-testid="daily-challenge-card"
      className={[
        "w-full rounded-2xl border p-3 flex items-center gap-3 transition-all duration-300",
        done
          ? "bg-emerald-500/[0.06] border-emerald-500/30"
          : "bg-slate-900/60 border-slate-800",
      ].join(" ")}
    >
      <div
        className={[
          "w-10 h-10 rounded-xl flex items-center justify-center shrink-0",
          done
            ? "bg-emerald-500/15 border border-emerald-500/30"
            : "bg-amber-500/10 border border-amber-500/30",
        ].join(" ")}
      >
        {done ? (
          <CheckCircle2 className="w-5 h-5 text-emerald-400" />
        ) : (
          <Flame className="w-5 h-5 text-amber-400" />
        )}
      </div>

      <button
        type="button"
        onClick={() => onPractice(challenge.surah, challenge.ayah)}
        data-testid="practice-daily-challenge-btn"
        className="flex-1 min-w-0 text-left"
      >
        <div className="flex items-center gap-2">
          <span
            className={[
              "text-[10px] uppercase tracking-[0.25em] font-semibold",
              done ? "text-emerald-400" : "text-amber-400",
            ].join(" ")}
          >
            Défi du jour
          </span>
          {streak > 1 && (
            <span
              data-testid="challenge-streak"
              className="text-[10px] text-slate-400 flex items-center gap-0.5"
            >
              <Flame className="w-3 h-3 text-amber-500" />
              {streak} j
            </span>
          )}
        </div>
        <div className="text-sm font-semibold text-slate-100 leading-tight mt-0.5 truncate">
          {challenge.surahName}, Verset {challenge.ayah}
        </div>
        <div className="text-[11px] text-slate-500 mt-0.5">
          {done ? "Complété — Barakallahu fik" : "Pratiquer ce verset"}
        </div>
      </button>

      {!done && (
        <ArrowRight className="w-4 h-4 text-slate-500 shrink-0" />
      )}
    </div>
  );
}
