import React, { useState } from "react";
import { Share2, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { shareVerse } from "../lib/share";
import { RECITERS } from "../data/surahs";

/**
 * Compact share button — generates a beautiful 1080x1080 image of the verse
 * and triggers the platform's native share sheet (or downloads + clipboard
 * fallback). Sadaqa jariya friendly: every share spreads a verse.
 */
export function ShareButton({ verse, reciter, disabled }) {
  const [loading, setLoading] = useState(false);

  const handleShare = async () => {
    if (!verse || loading || disabled) return;
    setLoading(true);
    try {
      const reciterMeta = RECITERS.find((r) => r.id === reciter) || RECITERS[0];
      const result = await shareVerse({
        surahName: verse.surahName,
        ayahNumber: verse.ayah,
        arabic: verse.arabic,
        french: verse.french,
        reciterName: reciterMeta.name,
      });
      if (result.method === "share") {
        toast.success("Partagé — qu'Allah accepte ta sadaqa.");
      } else if (result.method === "clipboard") {
        toast.success("Image téléchargée + texte copié");
      } else if (result.method === "download") {
        toast.success("Image téléchargée");
      } else if (result.method === "cancelled") {
        // user cancelled the share sheet — silent
      } else {
        toast.error("Le partage a échoué");
      }
    } catch (err) {
      console.error("[share]", err);
      toast.error("Impossible de générer l'image");
    } finally {
      setLoading(false);
    }
  };

  return (
    <button
      type="button"
      onClick={handleShare}
      disabled={disabled || loading || !verse}
      data-testid="share-verse-btn"
      aria-label="Partager le verset"
      className={[
        "w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 transition-all duration-300",
        "border border-indigo-500/40 bg-indigo-500/10 text-indigo-300",
        "hover:bg-indigo-500/20 active:scale-95",
        "disabled:opacity-40 disabled:cursor-not-allowed",
      ].join(" ")}
    >
      {loading ? (
        <Loader2 className="w-5 h-5 animate-spin" />
      ) : (
        <Share2 className="w-5 h-5" />
      )}
    </button>
  );
}
