import { useEffect, useRef, useState, useCallback } from "react";

/**
 * Audio loop hook — plays a single ayah audio file, repeats it N times,
 * or infinitely. Restarts instantly at end (no manual scrubbing).
 *
 * @param {string} url            Audio source URL (changes → reload).
 * @param {number|null} loops     Loop count (1, 3, 5, …). `null` or 0 → infinite.
 * @param {function} onComplete   Fired when a finite loop sequence completes naturally.
 */
export function useAudioLoop(url, loops, onComplete) {
  const audioRef = useRef(null);
  const playedRef = useRef(0); // completed plays
  const onCompleteRef = useRef(onComplete);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0); // 0..1
  const [loadState, setLoadState] = useState("idle"); // idle | loading | ready | error
  const [currentPlay, setCurrentPlay] = useState(0); // completed plays count

  // Keep latest onComplete in a ref to avoid re-wiring listeners
  useEffect(() => {
    onCompleteRef.current = onComplete;
  }, [onComplete]);

  // Create audio element once
  useEffect(() => {
    const audio = new Audio();
    audio.preload = "auto";
    audioRef.current = audio;
    return () => {
      audio.pause();
      audio.src = "";
      audioRef.current = null;
    };
  }, []);

  // Load new URL
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !url) return;
    setLoadState("loading");
    setProgress(0);
    playedRef.current = 0;
    setCurrentPlay(0);
    audio.src = url;
    audio.load();
  }, [url]);

  // Wire events
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const onCanPlay = () => setLoadState("ready");
    const onError = () => {
      setLoadState("error");
      setIsPlaying(false);
    };
    const onTime = () => {
      if (audio.duration > 0) setProgress(audio.currentTime / audio.duration);
    };
    const onEnded = () => {
      playedRef.current += 1;
      setCurrentPlay(playedRef.current);
      const infinite = !loops || loops <= 0;
      if (infinite || playedRef.current < loops) {
        // Instant restart — no scrubbing for the user
        audio.currentTime = 0;
        audio.play().catch(() => setIsPlaying(false));
      } else {
        setIsPlaying(false);
        setProgress(0);
        audio.currentTime = 0;
        playedRef.current = 0;
        setCurrentPlay(0);
        // Notify host that the configured loop sequence finished naturally
        onCompleteRef.current?.();
      }
    };

    audio.addEventListener("canplaythrough", onCanPlay);
    audio.addEventListener("error", onError);
    audio.addEventListener("timeupdate", onTime);
    audio.addEventListener("ended", onEnded);
    return () => {
      audio.removeEventListener("canplaythrough", onCanPlay);
      audio.removeEventListener("error", onError);
      audio.removeEventListener("timeupdate", onTime);
      audio.removeEventListener("ended", onEnded);
    };
  }, [loops]);

  const play = useCallback(() => {
    const audio = audioRef.current;
    if (!audio || !url) return;
    audio
      .play()
      .then(() => setIsPlaying(true))
      .catch(() => setIsPlaying(false));
  }, [url]);

  const pause = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.pause();
    setIsPlaying(false);
  }, []);

  const toggle = useCallback(() => {
    if (isPlaying) pause();
    else play();
  }, [isPlaying, play, pause]);

  const stop = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.pause();
    audio.currentTime = 0;
    playedRef.current = 0;
    setCurrentPlay(0);
    setIsPlaying(false);
    setProgress(0);
  }, []);

  return {
    isPlaying,
    progress,
    loadState,
    currentPlay,
    play,
    pause,
    toggle,
    stop,
  };
}
