import React from "react";
import { Loader2, Eye } from "lucide-react";

export function VerseDisplay({
  verse,
  loading,
  isPlaying,
  currentPlay,
  totalLoops,
  hiddenMode = false,
  revealed = false,
  onToggleReveal,
}) {
  const haloClass = isPlaying
    ? "ring-1 ring-emerald-500/50 shadow-[0_0_60px_rgba(16,185,129,0.18)]"
    : "ring-1 ring-slate-800/50";

  const isMasked = hiddenMode && !revealed;

  return (
    <div
      data-testid="verse-display"
      className={[
        "relative w-full rounded-3xl border border-slate-800/50 bg-slate-900/40 backdrop-blur-xl",
        "px-6 py-10 transition-all duration-700 ease-in-out",
        haloClass,
      ].join(" ")}
    >
      {/* Pulse overlay when playing */}
      {isPlaying && (
        <div className="absolute inset-0 rounded-3xl pointer-events-none animate-pulse bg-emerald-500/[0.02]" />
      )}

      {loading && (
        <div
          className="flex items-center justify-center min-h-[160px]"
          data-testid="verse-loading"
        >
          <Loader2 className="w-6 h-6 text-emerald-500/70 animate-spin" />
        </div>
      )}

      {!loading && verse && (
        <div className="flex flex-col gap-6 items-center text-center">
          {/* Surah label */}
          <div className="flex items-center gap-2 text-xs uppercase tracking-[0.25em] text-slate-500">
            <span>{verse.surahName}</span>
            <span className="text-slate-700">•</span>
            <span>Verset {verse.ayah}</span>
          </div>

          {/* Arabic text */}
          <p
            data-testid="verse-arabic"
            dir="rtl"
            lang="ar"
            style={{ fontFamily: "'Amiri', serif", lineHeight: 2.2 }}
            className={[
              "text-3xl sm:text-4xl text-slate-50 font-normal px-2 transition-all duration-500",
              isMasked ? "blur-md select-none opacity-70" : "blur-0",
            ].join(" ")}
          >
            {verse.arabic}
          </p>

          {/* Reveal action in hidden mode */}
          {hiddenMode && (
            <button
              type="button"
              onClick={onToggleReveal}
              data-testid="toggle-reveal-btn"
              className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-xs font-semibold uppercase tracking-widest bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 hover:bg-emerald-500/20 transition-all"
            >
              <Eye className="w-3.5 h-3.5" />
              {revealed ? "Masquer à nouveau" : "Révéler le verset"}
            </button>
          )}

          {/* Transliteration */}
          {verse.transliteration && !isMasked && (
            <p
              data-testid="verse-transliteration"
              className="text-sm sm:text-base text-slate-400 italic leading-relaxed px-2"
              style={{ fontFamily: "'Manrope', sans-serif" }}
            >
              {verse.transliteration}
            </p>
          )}

          {/* French translation */}
          {verse.french && !isMasked && (
            <p
              data-testid="verse-french"
              className="text-base sm:text-lg text-slate-300 leading-relaxed px-2"
              style={{ fontFamily: "'Manrope', sans-serif" }}
            >
              « {verse.french} »
            </p>
          )}

          {/* Loop counter while playing */}
          {isPlaying && (
            <div
              data-testid="loop-counter"
              className="text-xs text-emerald-400/80 tracking-widest uppercase mt-2"
            >
              {totalLoops > 0
                ? `Répétition ${currentPlay + 1} / ${totalLoops}`
                : `Répétition ${currentPlay + 1} • Boucle infinie`}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
