// AlQuran Cloud API wrapper (public + free)
// Docs: https://alquran.cloud/api

const BASE = "https://api.alquran.cloud/v1";

// In-memory caches
const ayahCache = new Map(); // key = `${surah}:${ayah}:${reciter}`
const pageCache = new Map(); // key = `${page}:${reciter}`

/**
 * Fetch a single ayah with Arabic text (Uthmani), French translation,
 * English transliteration, and audio URL for the selected reciter.
 */
export async function fetchAyah(surah, ayah, reciter = "ar.alafasy") {
  const key = `${surah}:${ayah}:${reciter}`;
  if (ayahCache.has(key)) return ayahCache.get(key);

  const editions = `quran-uthmani,fr.hamidullah,en.transliteration,${reciter}`;
  const url = `${BASE}/ayah/${surah}:${ayah}/editions/${editions}`;

  const res = await fetch(url);
  if (!res.ok) throw new Error(`Échec du chargement du verset (${res.status})`);
  const json = await res.json();
  if (json.code !== 200) throw new Error(json.status || "Erreur API");

  const editionsData = json.data;
  const arabic = editionsData.find((e) => e.edition.identifier === "quran-uthmani");
  const french = editionsData.find((e) => e.edition.identifier === "fr.hamidullah");
  const translit = editionsData.find((e) => e.edition.identifier === "en.transliteration");
  const audio = editionsData.find((e) => e.edition.identifier === reciter);

  const verse = {
    surah,
    ayah,
    arabic: arabic?.text || "",
    french: french?.text || "",
    transliteration: translit?.text || "",
    audioUrl: audio?.audio || audio?.audioSecondary?.[0] || "",
    surahName: arabic?.surah?.englishName || "",
    surahArabic: arabic?.surah?.name || "",
  };

  ayahCache.set(key, verse);
  return verse;
}

/**
 * Fetch a full mushaf page (1..604) with all its ayahs.
 * The API doesn't support multi-edition on the /page endpoint,
 * so we fan out parallel requests and merge by ayah number.
 */
export async function fetchPage(page, reciter = "ar.alafasy") {
  const key = `${page}:${reciter}`;
  if (pageCache.has(key)) return pageCache.get(key);

  const editions = ["quran-uthmani", "fr.hamidullah", reciter];
  const responses = await Promise.all(
    editions.map((ed) =>
      fetch(`${BASE}/page/${page}/${ed}`).then((r) => {
        if (!r.ok) throw new Error(`Erreur API (${r.status})`);
        return r.json();
      })
    )
  );

  if (responses.some((r) => r.code !== 200)) {
    throw new Error("Page introuvable");
  }

  const [arabicPage, frenchPage, audioPage] = responses.map((r) => r.data);

  // Merge by ayah.number (global ayah number)
  const byNumber = (list) => Object.fromEntries(list.map((a) => [a.number, a]));
  const ar = byNumber(arabicPage.ayahs);
  const fr = byNumber(frenchPage.ayahs);
  const au = byNumber(audioPage.ayahs);

  const ayahs = arabicPage.ayahs.map((a) => {
    const audio = au[a.number];
    return {
      globalNumber: a.number,
      surah: a.surah.number,
      surahName: a.surah.englishName,
      surahArabic: a.surah.name,
      ayah: a.numberInSurah,
      arabic: ar[a.number]?.text || "",
      french: fr[a.number]?.text || "",
      audioUrl: audio?.audio || audio?.audioSecondary?.[0] || "",
    };
  });

  const result = {
    page,
    ayahs,
    // Convenience: the first ayah's surah info for the page header
    firstSurah: ayahs[0]?.surah,
    firstSurahName: ayahs[0]?.surahName,
  };

  pageCache.set(key, result);
  return result;
}

