function CopyRow({ label, value, extra, mono, testid }) {
  const [copied, setCopied] = useState(false);

  const onCopy = async () => {
    try {
      await navigator.clipboard.writeText(value);
      setCopied(true);
      toast.success(`${label} copié`);
      setTimeout(() => setCopied(false), 1800);
    } catch {
      toast.error("Impossible de copier — copie manuelle requise");
    }
  };

  return (
    <div className="flex items-start gap-2">
      <div className="flex-1 min-w-0">
        <div className="text-[10px] uppercase tracking-widest text-slate-500 mb-1">
          {label}
        </div>
        <div
          className={[
            "text-sm text-slate-100 leading-tight break-all",
            mono ? "font-mono tracking-tight" : "",
          ].join(" ")}
        >
          {value}
        </div>
        {extra && (
          <div className="text-[11px] text-slate-500 mt-0.5">{extra}</div>
        )}
      </div>
      <button
        type="button"
        onClick={onCopy}
        data-testid={testid}
        aria-label={`Copier ${label}`}
        className="shrink-0 mt-3 w-9 h-9 rounded-xl bg-slate-800/70 border border-slate-700 flex items-center justify-center text-slate-300 hover:border-emerald-500/40 hover:text-emerald-300 transition-all"
      >
        {copied ? <Check className="w-4 h-4 text-emerald-400" /> : <Copy className="w-4 h-4" />}
      </button>
    </div>
  );
}

function QrSection() {
  const [amount, setAmount] = useState("");
  const [showAmount, setShowAmount] = useState(false);
  const qrUrl = sepaQrImageUrl({ amountEur: amount, size: 280 });

  return (
    <section
      data-testid="donation-qr"
      className="rounded-2xl bg-slate-900/60 border border-slate-800 p-4"
    >
      <div className="text-[11px] uppercase tracking-[0.25em] text-emerald-400 flex items-center gap-1.5 mb-2">
        <ScanLine className="w-3.5 h-3.5" />
        QR SEPA — scan dans ton app bancaire
      </div>
      <p className="text-[11px] text-slate-500 mb-3 leading-relaxed">
        Compatible avec la plupart des banques françaises pour pré-remplir
        automatiquement le virement.
      </p>
      <div className="flex justify-center mb-3">
        <div className="rounded-xl bg-slate-950 border border-emerald-500/20 p-2 inline-block">
          <img
            src={qrUrl}
            alt="QR code SEPA pour don à Firkate Nadjiyat"
            data-testid="donation-qr-img"
            width={240}
            height={240}
            className="block"
            loading="lazy"
          />
        </div>
      </div>

      <button
        type="button"
        onClick={() => setShowAmount((v) => !v)}
        data-testid="toggle-amount-btn"
        className="text-[11px] text-emerald-400 hover:text-emerald-300 underline-offset-2 hover:underline mx-auto block"
      >
        {showAmount ? "Masquer le montant" : "Pré-remplir un montant (optionnel)"}
      </button>

      {showAmount && (
        <div className="mt-3 flex items-center gap-2" data-testid="amount-row">
          <input
            type="number"
            inputMode="decimal"
            min="0"
            step="1"
            value={amount}
            onChange={(e) => setAmount(e.target.value.replace(/[^0-9.]/g, ""))}
            placeholder="ex: 20"
            data-testid="amount-input"
            className="flex-1 h-10 px-3 rounded-xl bg-slate-950 border border-slate-700 text-slate-100 text-sm focus:outline-none focus:border-emerald-500/60"
          />
          <span className="text-sm text-slate-400">€</span>
          <div className="flex gap-1">
            {[5, 20, 50].map((v) => (
              <button
                key={v}
                type="button"
                onClick={() => setAmount(String(v))}
                data-testid={`amount-preset-${v}`}
                className="px-2 h-8 rounded-lg text-[11px] bg-slate-800 border border-slate-700 text-slate-300 hover:border-emerald-500/40"
              >
                {v}€
              </button>
            ))}
          </div>
        </div>
      )}
    </section>
  );
}
