import React, { useEffect, useRef } from "react";
import { RECITERS } from "../data/surahs";

export function ReciterSelector({ reciter, onChange }) {
  const scrollRef = useRef(null);

  // Auto-scroll active pill into view when the selection changes
  useEffect(() => {
    const el = scrollRef.current?.querySelector(`[data-reciter-id="${reciter}"]`);
    el?.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "center" });
  }, [reciter]);

  return (
    <div className="flex flex-col gap-2" data-testid="reciter-selector">
      <span className="text-xs uppercase tracking-widest text-slate-500">
        Récitateur
      </span>
      <div
        ref={scrollRef}
        className="flex gap-2 overflow-x-auto pb-1 -mx-1 px-1 snap-x snap-mandatory scrollbar-none"
        style={{ scrollbarWidth: "none" }}
      >
        {RECITERS.map((r) => {
          const active = r.id === reciter;
          return (
            <button
              key={r.id}
              type="button"
              data-testid={`reciter-${r.id}`}
              data-reciter-id={r.id}
              onClick={() => onChange(r.id)}
              className={[
                "shrink-0 snap-start rounded-2xl px-3 py-2 text-left transition-all duration-300",
                "border min-w-[150px] max-w-[180px]",
                active
                  ? "bg-emerald-500/10 border-emerald-500/40 text-emerald-300"
                  : "bg-slate-900/60 border-slate-800 text-slate-300 hover:border-slate-700",
              ].join(" ")}
            >
              <div className="text-[13px] font-semibold leading-tight truncate">
                {r.name}
              </div>
              <div className="text-[10px] text-slate-500 mt-0.5 leading-tight line-clamp-2">
                {r.description}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}
