import React from "react";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "./ui/sheet";
import { BarChart3 } from "lucide-react";
import { getStats } from "../lib/srs";

export function StatsSheet({ refreshKey }) {
  const stats = getStats();
  void refreshKey;

  return (
    <Sheet>
      <SheetTrigger asChild>
        <button
          type="button"
          data-testid="open-stats-btn"
          className="flex items-center gap-2 px-3 py-2 rounded-full bg-slate-900/70 border border-slate-800 text-slate-300 hover:border-indigo-500/40 transition-all text-sm"
        >
          <BarChart3 className="w-4 h-4" />
          Stats
        </button>
      </SheetTrigger>
      <SheetContent
        side="bottom"
        className="bg-slate-950 border-slate-800 text-slate-100 rounded-t-3xl"
        data-testid="stats-sheet"
      >
        <SheetHeader>
          <SheetTitle className="text-slate-100 text-left">
            Statistiques de mémorisation
          </SheetTitle>
          <SheetDescription className="text-slate-500 text-left text-xs">
            Aperçu de ta progression dans la mémorisation du Coran.
          </SheetDescription>
        </SheetHeader>

        <div className="mt-6 flex flex-col gap-3">
          <StatRow label="Versets suivis" value={stats.total} accent="emerald" testid="stat-total" />
          <StatRow label="À réviser maintenant" value={stats.due} accent="emerald" testid="stat-due" />
          <StatRow label="En apprentissage" value={stats.learning} accent="indigo" testid="stat-learning" />
          <StatRow label="Maîtrisés (niveau ≥ 5)" value={stats.mastered} accent="emerald" testid="stat-mastered" />
          <StatRow label="Révisions totales" value={stats.totalReviews} accent="slate" testid="stat-reviews" />
        </div>

        <p className="text-[11px] text-slate-500 italic mt-6 leading-relaxed">
          « Le meilleur d&apos;entre vous est celui qui apprend le Coran et l&apos;enseigne. »
          <br />
          — Sahih al-Bukhari
        </p>
      </SheetContent>
    </Sheet>
  );
}

function StatRow({ label, value, accent, testid }) {
  const colorMap = {
    emerald: "text-emerald-400",
    indigo: "text-indigo-400",
    slate: "text-slate-300",
  };
  return (
    <div
      data-testid={testid}
      className="flex items-center justify-between rounded-2xl bg-slate-900/60 border border-slate-800 px-4 py-3"
    >
      <span className="text-sm text-slate-400">{label}</span>
      <span className={`text-2xl font-bold ${colorMap[accent] || "text-slate-100"}`}>
        {value}
      </span>
    </div>
  );
}
