import React from "react";
import { Play, Pause, ChevronLeft, ChevronRight, Loader2, Infinity as InfinityIcon } from "lucide-react";

const LOOP_OPTIONS = [
  { value: 1, label: "1x" },
  { value: 3, label: "3x" },
  { value: 5, label: "5x" },
  { value: 0, label: "∞", infinite: true },
];

export function AudioConsole({
  isPlaying,
  loadState,
  onToggle,
  onPrev,
  onNext,
  canPrev,
  canNext,
  loops,
  onLoopChange,
  progress,
}) {
  const isLoading = loadState === "loading";
  const hasError = loadState === "error";

  return (
    <div className="w-full flex flex-col items-center gap-5" data-testid="audio-console">
      {/* Loop selector pills */}
      <div className="flex items-center gap-2 w-full justify-center" data-testid="loop-selector">
        <span className="text-[10px] uppercase tracking-[0.25em] text-slate-500 mr-1">
          Boucle
        </span>
        {LOOP_OPTIONS.map((opt) => {
          const active = loops === opt.value;
          return (
            <button
              key={opt.label}
              type="button"
              data-testid={`loop-selector-${opt.infinite ? "infinite" : opt.value + "x"}`}
              onClick={() => onLoopChange(opt.value)}
              className={[
                "min-w-[48px] h-9 px-3 rounded-full text-sm font-semibold transition-all duration-300",
                "border",
                active
                  ? "bg-indigo-600 border-indigo-500 text-white shadow-md shadow-indigo-500/30"
                  : "bg-slate-900/70 border-slate-800 text-slate-300 hover:border-indigo-500/40",
              ].join(" ")}
            >
              {opt.infinite ? (
                <InfinityIcon className="w-4 h-4 mx-auto" />
              ) : (
                opt.label
              )}
            </button>
          );
        })}
      </div>

      {/* Main controls row */}
      <div className="flex items-center justify-center gap-6 w-full">
        <button
          type="button"
          data-testid="prev-ayah-btn"
          onClick={onPrev}
          disabled={!canPrev}
          className="w-12 h-12 rounded-full bg-slate-900/70 border border-slate-800 flex items-center justify-center text-slate-300 hover:border-slate-700 disabled:opacity-30 disabled:cursor-not-allowed transition-all"
          aria-label="Verset précédent"
        >
          <ChevronLeft className="w-5 h-5" />
        </button>

        {/* Massive thumb-friendly play/pause */}
        <button
          type="button"
          data-testid="play-pause-btn"
          onClick={onToggle}
          disabled={hasError}
          className={[
            "relative w-20 h-20 rounded-full flex items-center justify-center",
            "transition-all duration-300 active:scale-95",
            hasError
              ? "bg-rose-900/40 text-rose-300 border border-rose-800"
              : "bg-indigo-600 hover:bg-indigo-500 text-white shadow-xl shadow-indigo-500/30",
          ].join(" ")}
          aria-label={isPlaying ? "Pause" : "Lecture"}
        >
          {/* Circular progress ring */}
          {!isLoading && !hasError && (
            <svg
              className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none"
              viewBox="0 0 100 100"
            >
              <circle
                cx="50"
                cy="50"
                r="46"
                fill="none"
                stroke="rgba(255,255,255,0.15)"
                strokeWidth="2"
              />
              <circle
                cx="50"
                cy="50"
                r="46"
                fill="none"
                stroke="rgba(255,255,255,0.85)"
                strokeWidth="2"
                strokeLinecap="round"
                strokeDasharray={`${2 * Math.PI * 46}`}
                strokeDashoffset={`${2 * Math.PI * 46 * (1 - (progress || 0))}`}
                style={{ transition: "stroke-dashoffset 0.15s linear" }}
              />
            </svg>
          )}

          {isLoading ? (
            <Loader2 className="w-8 h-8 animate-spin" />
          ) : isPlaying ? (
            <Pause className="w-8 h-8" fill="currentColor" />
          ) : (
            <Play className="w-8 h-8 ml-1" fill="currentColor" />
          )}
        </button>

        <button
          type="button"
          data-testid="next-ayah-btn"
          onClick={onNext}
          disabled={!canNext}
          className="w-12 h-12 rounded-full bg-slate-900/70 border border-slate-800 flex items-center justify-center text-slate-300 hover:border-slate-700 disabled:opacity-30 disabled:cursor-not-allowed transition-all"
          aria-label="Verset suivant"
        >
          <ChevronRight className="w-5 h-5" />
        </button>
      </div>

      {hasError && (
        <p
          className="text-xs text-rose-400 text-center"
          data-testid="audio-error"
        >
          Audio indisponible. Vérifiez votre connexion.
        </p>
      )}
    </div>
  );
}
