// Daily challenge: pick a deterministic verse from Juz Amma (sourates 78-114)
// based on today's date so all users in the same day get the same challenge.

import { SURAHS } from "../data/surahs";

const STORAGE_KEY = "hifz.challenge.v1";

// Build flat list of all Juz Amma verses
const JUZ_AMMA = SURAHS.filter((s) => s.number >= 78 && s.number <= 114);
const JUZ_AMMA_VERSES = JUZ_AMMA.flatMap((s) =>
  Array.from({ length: s.ayahs }, (_, i) => ({
    surah: s.number,
    ayah: i + 1,
    surahName: s.name,
    surahFrench: s.french,
    surahAyahCount: s.ayahs,
  }))
);

export const JUZ_AMMA_TOTAL = JUZ_AMMA_VERSES.length;

function todayKey() {
  const d = new Date();
  return `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
}

function dayHash() {
  const d = new Date();
  // Mulberry-ish small mix of (year, month, day)
  const y = d.getFullYear();
  const m = d.getMonth();
  const dd = d.getDate();
  let h = y * 73856093;
  h = (h ^ (m * 19349663)) >>> 0;
  h = (h ^ (dd * 83492791)) >>> 0;
  return h;
}

/** Returns today's challenge verse — deterministic per calendar day. */
export function getDailyChallenge() {
  const idx = dayHash() % JUZ_AMMA_VERSES.length;
  return JUZ_AMMA_VERSES[idx];
}

function loadState() {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}");
  } catch {
    return {};
  }
}

function saveState(patch) {
  const next = { ...loadState(), ...patch };
  localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
  return next;
}

export function isChallengeDoneToday() {
  const s = loadState();
  return s.lastDoneDay === todayKey();
}

export function markChallengeDone() {
  saveState({ lastDoneDay: todayKey() });
}

/** Returns the all-time streak count of consecutive days the challenge was completed. */
export function getChallengeStreak() {
  const s = loadState();
  return s.streak || 0;
}

/**
 * Update the streak. Called when the daily challenge is completed.
 * Increments if yesterday's challenge was also done; resets to 1 otherwise.
 */
export function bumpStreak() {
  const s = loadState();
  const today = todayKey();
  if (s.lastDoneDay === today) return s.streak || 0; // already counted

  const yesterday = (() => {
    const d = new Date();
    d.setDate(d.getDate() - 1);
    return `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
  })();

  const newStreak = s.lastDoneDay === yesterday ? (s.streak || 0) + 1 : 1;
  saveState({ lastDoneDay: today, streak: newStreak });
  return newStreak;
}
