// Browser notification helpers for daily SRS review reminders.
// No backend / push: shows a local notification when the user opens the app
// and there are due cards and they haven't been notified today.

const STORE_KEY = "hifz.notif.v1";

export function loadNotifState() {
  try {
    return JSON.parse(localStorage.getItem(STORE_KEY) || "{}");
  } catch {
    return {};
  }
}

export function saveNotifState(patch) {
  const next = { ...loadNotifState(), ...patch };
  localStorage.setItem(STORE_KEY, JSON.stringify(next));
  return next;
}

export function getPermission() {
  if (typeof window === "undefined" || !("Notification" in window)) return "unsupported";
  return Notification.permission; // "default" | "granted" | "denied"
}

export async function requestPermission() {
  if (typeof window === "undefined" || !("Notification" in window)) return "unsupported";
  if (Notification.permission === "granted") return "granted";
  const result = await Notification.requestPermission();
  return result;
}

function todayKey() {
  const d = new Date();
  return `${d.getFullYear()}-${d.getMonth() + 1}-${d.getDate()}`;
}

/**
 * Show a local "X versets à réviser aujourd'hui" notification.
 * Only fires if permission is granted AND we haven't notified today AND
 * the user's chosen reminder hour has passed.
 */
export async function maybeShowDailyReminder(dueCount, reminderHour = 9) {
  if (dueCount <= 0) return { fired: false, reason: "no-due" };
  if (getPermission() !== "granted") return { fired: false, reason: "no-permission" };
  const state = loadNotifState();
  if (!state.enabled) return { fired: false, reason: "disabled" };
  if (state.lastNotifiedDay === todayKey())
    return { fired: false, reason: "already-today" };
  const now = new Date();
  if (now.getHours() < reminderHour) return { fired: false, reason: "before-hour" };

  await showNotification(
    `${dueCount} verset${dueCount > 1 ? "s" : ""} à réviser`,
    {
      body:
        dueCount > 1
          ? `Tu as ${dueCount} versets à réviser aujourd'hui. Qu'Allah te facilite.`
          : "Un verset attend ta révision aujourd'hui. Qu'Allah te facilite.",
      tag: "hifz-daily",
      icon: "/icon-192.png",
      badge: "/icon-192.png",
    }
  );
  saveNotifState({ lastNotifiedDay: todayKey() });
  return { fired: true };
}

export async function showTestNotification() {
  if (getPermission() !== "granted") {
    const r = await requestPermission();
    if (r !== "granted") return false;
  }
  await showNotification("Hifz Sentinel — Test", {
    body: "Les rappels fonctionnent. Qu'Allah accepte ton effort.",
    tag: "hifz-test",
    icon: "/icon-192.png",
  });
  return true;
}

async function showNotification(title, options) {
  // Prefer SW registration so it survives tab close on some platforms
  if ("serviceWorker" in navigator) {
    try {
      const reg = await navigator.serviceWorker.getRegistration();
      if (reg) {
        await reg.showNotification(title, options);
        return;
      }
    } catch (err) {
      // Fall back to direct Notification API below; log for diagnostics.
      if (process.env.NODE_ENV !== "production") {
        console.warn("[hifz] SW notification failed, using fallback:", err);
      }
    }
  }
  new Notification(title, options);
}

export async function registerServiceWorker() {
  if (!("serviceWorker" in navigator)) return null;
  try {
    const reg = await navigator.serviceWorker.register("/sw.js");
    return reg;
  } catch (e) {
    console.warn("[hifz] SW registration failed:", e);
    return null;
  }
}
