import React from "react";
import {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "./ui/select";
import { SURAHS } from "../data/surahs";

export function SurahAyahSelector({ surah, ayah, onSurahChange, onAyahChange }) {
  const current = SURAHS.find((s) => s.number === surah) || SURAHS[0];
  const ayahCount = current.ayahs;

  return (
    <div className="flex gap-3 w-full" data-testid="surah-ayah-selector">
      {/* Sélecteur de Sourate */}
      <div className="flex-[2]">
        <label className="text-xs uppercase tracking-widest text-slate-500 mb-2 block">
          Sourate
        </label>
        <Select
          value={String(surah)}
          onValueChange={(v) => onSurahChange(parseInt(v, 10))}
        >
          <SelectTrigger
            data-testid="surah-selector-trigger"
            className="h-14 rounded-2xl bg-slate-900/70 border-slate-800 text-slate-100 focus:ring-emerald-500/40"
          >
            <SelectValue />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-slate-800 text-slate-100 max-h-80">
            <SelectGroup>
              {SURAHS.map((s) => (
                <SelectItem
                  key={s.number}
                  value={String(s.number)}
                  data-testid={`surah-option-${s.number}`}
                  className="focus:bg-emerald-500/10 focus:text-emerald-300"
                >
                  <span className="font-medium">{s.number}. {s.name}</span>
                  <span className="text-slate-500 text-xs ml-2">— {s.french}</span>
                </SelectItem>
              ))}
            </SelectGroup>
          </SelectContent>
        </Select>
      </div>

      {/* Sélecteur de Verset */}
      <div className="flex-1">
        <label className="text-xs uppercase tracking-widest text-slate-500 mb-2 block">
          Verset
        </label>
        <Select value={String(ayah)} onValueChange={(v) => onAyahChange(parseInt(v, 10))}>
          <SelectTrigger
            data-testid="ayah-selector-trigger"
            className="h-14 rounded-2xl bg-slate-900/70 border-slate-800 text-slate-100 focus:ring-emerald-500/40"
          >
            <SelectValue />
          </SelectTrigger>
          <SelectContent className="bg-slate-900 border-slate-800 text-slate-100 max-h-80">
            <SelectGroup>
              {Array.from({ length: ayahCount }, (_, i) => i + 1).map((n) => (
                <SelectItem
                  key={n}
                  value={String(n)}
                  data-testid={`ayah-option-${n}`}
                  className="focus:bg-emerald-500/10 focus:text-emerald-300"
                >
                  {n}
                </SelectItem>
              ))}
            </SelectGroup>
          </SelectContent>
        </Select>
      </div>
    </div>
  );
}
