import React from "react";
import { ReciterSelector } from "./ReciterSelector";
import { MushafView } from "./MushafView";

/**
 * Mushaf (page-by-page) practice section. Wraps the reciter picker and the
 * mushaf page renderer.
 */
export function MushafSection({
  reciter,
  onReciterChange,
  mushafPage,
  onPageChange,
  activeSurah,
  activeAyah,
  onSelectAyah,
  isPlaying,
  currentPlay,
  loops,
  onTogglePlay,
}) {
  return (
    <>
      <section className="mb-4">
        <ReciterSelector reciter={reciter} onChange={onReciterChange} />
      </section>

      <section className="mb-5 flex-1">
        <MushafView
          page={mushafPage}
          onPageChange={onPageChange}
          reciter={reciter}
          activeSurah={activeSurah}
          activeAyah={activeAyah}
          onSelectAyah={onSelectAyah}
          isPlaying={isPlaying}
          currentPlay={currentPlay}
          totalLoops={loops}
          onTogglePlay={onTogglePlay}
        />
      </section>
    </>
  );
}
