import React, { useState } from "react";
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "./ui/sheet";
import { Bell, BellOff, BellRing } from "lucide-react";
import { toast } from "sonner";
import {
  getPermission,
  requestPermission,
  loadNotifState,
  saveNotifState,
  showTestNotification,
} from "../lib/notifications";

export function NotificationSettings({ dueCount }) {
  const initial = loadNotifState();
  const [enabled, setEnabled] = useState(!!initial.enabled);
  const [hour, setHour] = useState(initial.reminderHour ?? 9);
  const [permission, setPermission] = useState(getPermission());

  const onEnableChange = async (next) => {
    if (next) {
      const p = await requestPermission();
      setPermission(p);
      if (p !== "granted") {
        toast.error("Permission refusée par le navigateur");
        return;
      }
    }
    setEnabled(next);
    saveNotifState({ enabled: next, reminderHour: hour });
    toast.success(next ? "Rappels activés" : "Rappels désactivés");
  };

  const onHourChange = (h) => {
    setHour(h);
    saveNotifState({ reminderHour: h });
  };

  const onTest = async () => {
    const ok = await showTestNotification();
    setPermission(getPermission());
    if (!ok) toast.error("Impossible — vérifiez les permissions du navigateur");
  };

  const supported = permission !== "unsupported";

  return (
    <Sheet>
      <SheetTrigger asChild>
        <button
          type="button"
          data-testid="open-notif-settings-btn"
          className="flex items-center gap-2 px-3 py-2 rounded-full bg-slate-900/70 border border-slate-800 text-slate-300 hover:border-amber-500/40 transition-all text-sm"
        >
          {enabled && permission === "granted" ? (
            <BellRing className="w-4 h-4 text-amber-400" />
          ) : (
            <Bell className="w-4 h-4" />
          )}
          Rappels
        </button>
      </SheetTrigger>
      <SheetContent
        side="bottom"
        className="bg-slate-950 border-slate-800 text-slate-100 rounded-t-3xl"
        data-testid="notif-settings-sheet"
      >
        <SheetHeader>
          <SheetTitle className="text-slate-100 text-left">
            Rappels de révision
          </SheetTitle>
          <SheetDescription className="text-slate-500 text-left text-xs">
            Une notification à l&apos;ouverture de l&apos;app quand des versets attendent.
          </SheetDescription>
        </SheetHeader>

        {!supported && (
          <div
            className="mt-4 p-3 rounded-2xl border border-amber-500/30 bg-amber-500/5 text-amber-300 text-xs flex items-start gap-2"
            data-testid="notif-unsupported"
          >
            <BellOff className="w-4 h-4 mt-0.5 shrink-0" />
            <span>
              Ton navigateur ne supporte pas les notifications. Tu verras
              toujours la bannière de rappel dans l&apos;app.
            </span>
          </div>
        )}

        {supported && (
          <div className="mt-5 flex flex-col gap-4">
            <label
              className="flex items-center justify-between rounded-2xl bg-slate-900/70 border border-slate-800 p-4 cursor-pointer"
              data-testid="notif-enable-row"
            >
              <div className="flex-1 mr-3">
                <div className="text-sm font-semibold">Activer les rappels</div>
                <div className="text-xs text-slate-500 mt-0.5">
                  Statut :{" "}
                  <span
                    className={
                      permission === "granted"
                        ? "text-emerald-400"
                        : permission === "denied"
                        ? "text-rose-400"
                        : "text-slate-400"
                    }
                  >
                    {permission === "granted"
                      ? "Autorisé"
                      : permission === "denied"
                      ? "Refusé (à activer dans le navigateur)"
                      : "Non demandé"}
                  </span>
                </div>
              </div>
              <input
                type="checkbox"
                checked={enabled}
                onChange={(e) => onEnableChange(e.target.checked)}
                data-testid="notif-enable-checkbox"
                className="w-5 h-5 accent-emerald-500"
              />
            </label>

            <div className="rounded-2xl bg-slate-900/70 border border-slate-800 p-4">
              <div className="text-sm font-semibold mb-1">Heure du rappel</div>
              <div className="text-xs text-slate-500 mb-3">
                Le rappel apparaît à la première ouverture après cette heure.
              </div>
              <div className="flex items-center gap-2" data-testid="notif-hour-row">
                <input
                  type="range"
                  min={0}
                  max={23}
                  value={hour}
                  onChange={(e) => onHourChange(parseInt(e.target.value, 10))}
                  data-testid="notif-hour-slider"
                  className="flex-1 accent-amber-400"
                />
                <span className="w-14 text-right text-amber-300 font-semibold tabular-nums">
                  {String(hour).padStart(2, "0")}:00
                </span>
              </div>
            </div>

            <button
              type="button"
              onClick={onTest}
              data-testid="notif-test-btn"
              className="w-full h-12 rounded-2xl bg-amber-500/10 border border-amber-500/30 text-amber-300 text-sm font-semibold hover:bg-amber-500/15 transition-all flex items-center justify-center gap-2"
            >
              <BellRing className="w-4 h-4" />
              Tester maintenant
            </button>

            <p className="text-[11px] text-slate-500 leading-relaxed">
              Note : tant que tu n&apos;ouvres pas l&apos;app, le rappel ne s&apos;affichera
              pas (pas de serveur push, projet 100% bénévole). Le compteur du
              bouton « Révision » reste précis.
            </p>
            {dueCount > 0 && (
              <p
                className="text-[11px] text-emerald-400 leading-relaxed"
                data-testid="notif-due-hint"
              >
                Actuellement : {dueCount} verset{dueCount > 1 ? "s" : ""} en
                attente de révision.
              </p>
            )}
          </div>
        )}
      </SheetContent>
    </Sheet>
  );
}
