import React from "react";
import { SurahAyahSelector } from "./SurahAyahSelector";
import { ReciterSelector } from "./ReciterSelector";
import { ModeToggles } from "./ModeToggles";
import { VerseDisplay } from "./VerseDisplay";

/**
 * Verse-by-verse practice view (default mode). Composes the selectors,
 * reciter picker, mode toggles, and verse display.
 */
export function VersetSection({
  surah,
  ayah,
  onSurahChange,
  onAyahChange,
  reciter,
  onReciterChange,
  autoAdvance,
  onAutoAdvanceChange,
  hiddenMode,
  onHiddenModeChange,
  revealed,
  onToggleReveal,
  verse,
  loading,
  isPlaying,
  currentPlay,
  loops,
}) {
  return (
    <>
      <section className="mb-4">
        <SurahAyahSelector
          surah={surah}
          ayah={ayah}
          onSurahChange={onSurahChange}
          onAyahChange={onAyahChange}
        />
      </section>

      <section className="mb-4">
        <ReciterSelector reciter={reciter} onChange={onReciterChange} />
      </section>

      <section className="mb-5">
        <ModeToggles
          autoAdvance={autoAdvance}
          onAutoAdvanceChange={onAutoAdvanceChange}
          hiddenMode={hiddenMode}
          onHiddenModeChange={onHiddenModeChange}
        />
      </section>

      <section className="mb-5 flex-1 flex">
        <VerseDisplay
          verse={verse}
          loading={loading}
          isPlaying={isPlaying}
          currentPlay={currentPlay}
          totalLoops={loops}
          hiddenMode={hiddenMode}
          revealed={revealed}
          onToggleReveal={onToggleReveal}
        />
      </section>
    </>
  );
}
