/**
 * Returns the IBAN without spaces — required for SEPA payments.
 */
export function ibanCompact(iban) {
  return iban.replace(/\s+/g, "");
}

/**
 * Build a EPC069-12 (SEPA Credit Transfer) payload that French / European
 * banking apps can scan via QR to pre-fill a virement form.
 * Spec: https://en.wikipedia.org/wiki/EPC_QR_code
 */
export function buildSepaQrPayload({ amountEur = "", reference = "Don Firkate Nadjiyat" } = {}) {
  const lines = [
    "BCD",                              // Service Tag
    "002",                              // Version
    "1",                                // Encoding (1 = UTF-8)
    "SCT",                              // Identification (SEPA Credit Transfer)
    ASSOCIATION.bank.bic,               // BIC
    ASSOCIATION.bank.holder,            // Beneficiary name (max 70 chars)
    ibanCompact(ASSOCIATION.bank.iban), // IBAN
    amountEur ? `EUR${Number(amountEur).toFixed(2)}` : "", // Amount (optional)
    "CHAR",                             // Purpose
    "",                                 // Structured remittance reference
    reference,                          // Unstructured remittance info
  ];
  return lines.join("\n");
}

/**
 * Build a URL that returns a PNG QR code of the SEPA payload.
 * Uses the free public goqr.me API — no key required, no client dependency.
 */
export function sepaQrImageUrl({ size = 280, amountEur = "", reference } = {}) {
  const payload = buildSepaQrPayload({ amountEur, reference });
  return `https://api.qrserver.com/v1/create-qr-code/?data=${encodeURIComponent(
    payload
  )}&size=${size}x${size}&margin=4&format=png&bgcolor=020617&color=10b981`;
}
