import React from "react";
import { Eye, EyeOff, ListVideo, SkipForward } from "lucide-react";

/**
 * Compact row of practice mode toggles:
 *  - Auto-advance: play next ayah after the loop sequence completes
 *  - Hidden mode: blur the Arabic text to self-test memorization
 */
export function ModeToggles({
  autoAdvance,
  onAutoAdvanceChange,
  hiddenMode,
  onHiddenModeChange,
}) {
  return (
    <div
      className="flex items-stretch gap-2 w-full"
      data-testid="mode-toggles"
    >
      <ModePill
        active={autoAdvance}
        onClick={() => onAutoAdvanceChange(!autoAdvance)}
        icon={autoAdvance ? <SkipForward className="w-4 h-4" /> : <ListVideo className="w-4 h-4" />}
        label="Lecture continue"
        sublabel={autoAdvance ? "Verset suivant auto" : "Reste sur ce verset"}
        accent="indigo"
        testid="auto-advance-toggle"
      />
      <ModePill
        active={hiddenMode}
        onClick={() => onHiddenModeChange(!hiddenMode)}
        icon={hiddenMode ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
        label="Mode test"
        sublabel={hiddenMode ? "Verset masqué" : "Verset visible"}
        accent="emerald"
        testid="hidden-mode-toggle"
      />
    </div>
  );
}

function ModePill({ active, onClick, icon, label, sublabel, accent, testid }) {
  const accentMap = {
    indigo: {
      on: "bg-indigo-500/15 border-indigo-500/40 text-indigo-300",
      off: "bg-slate-900/60 border-slate-800 text-slate-400",
    },
    emerald: {
      on: "bg-emerald-500/15 border-emerald-500/40 text-emerald-300",
      off: "bg-slate-900/60 border-slate-800 text-slate-400",
    },
  };
  const a = accentMap[accent] || accentMap.indigo;
  return (
    <button
      type="button"
      onClick={onClick}
      data-testid={testid}
      aria-pressed={active}
      className={[
        "flex-1 rounded-2xl px-3 py-2.5 text-left transition-all duration-300",
        "border flex items-center gap-2.5",
        active ? a.on : a.off,
        "hover:border-slate-700",
      ].join(" ")}
    >
      <div
        className={[
          "w-7 h-7 rounded-full flex items-center justify-center shrink-0",
          active ? "bg-slate-950/40" : "bg-slate-800/60",
        ].join(" ")}
      >
        {icon}
      </div>
      <div className="min-w-0 flex-1">
        <div className="text-[12px] font-semibold leading-tight truncate">{label}</div>
        <div className="text-[10px] opacity-70 leading-tight mt-0.5 truncate">
          {sublabel}
        </div>
      </div>
    </button>
  );
}
