// Share a verse: generates a 1080x1080 image (canvas) and either uses the
// Web Share API (preferred, mobile-friendly) or falls back to a download
// + clipboard copy.

const APP_URL = (typeof window !== "undefined" && window.location.origin) || "";
const APP_NAME = "Hifz & Récitation Sentinel";

/** Wrap text for canvas (works for RTL too — caller sets ctx.direction). */
function wrapLines(ctx, text, maxWidth) {
  const words = text.split(/\s+/);
  const lines = [];
  let line = "";
  for (const w of words) {
    const tentative = line ? `${line} ${w}` : w;
    const { width } = ctx.measureText(tentative);
    if (width > maxWidth && line) {
      lines.push(line);
      line = w;
    } else {
      line = tentative;
    }
  }
  if (line) lines.push(line);
  return lines;
}

/** Draw an array of lines centered around `centerX, startY` with line height `lh`. */
function drawLines(ctx, lines, centerX, startY, lh) {
  lines.forEach((l, i) => {
    ctx.fillText(l, centerX, startY + i * lh);
  });
  return startY + lines.length * lh;
}

async function ensureFontsReady() {
  if (!("fonts" in document)) return;
  try {
    await Promise.all([
      document.fonts.load("700 56px Amiri"),
      document.fonts.load("500 32px Manrope"),
      document.fonts.load("italic 400 28px Manrope"),
      document.fonts.load("600 22px Outfit"),
    ]);
    await document.fonts.ready;
  } catch {
    /* best-effort */
  }
}

export async function generateVerseImage({
  surahName,
  ayahNumber,
  arabic,
  french,
  reciterName,
}) {
  await ensureFontsReady();

  const W = 1080;
  const H = 1080;
  const canvas = document.createElement("canvas");
  canvas.width = W;
  canvas.height = H;
  const ctx = canvas.getContext("2d");

  // Background — solid slate-950
  ctx.fillStyle = "#020617";
  ctx.fillRect(0, 0, W, H);

  // Soft emerald glow top-left
  const g1 = ctx.createRadialGradient(180, 100, 50, 180, 100, 700);
  g1.addColorStop(0, "rgba(16, 185, 129, 0.18)");
  g1.addColorStop(1, "rgba(16, 185, 129, 0)");
  ctx.fillStyle = g1;
  ctx.fillRect(0, 0, W, H);

  // Soft indigo glow bottom-right
  const g2 = ctx.createRadialGradient(900, 950, 50, 900, 950, 600);
  g2.addColorStop(0, "rgba(99, 102, 241, 0.16)");
  g2.addColorStop(1, "rgba(99, 102, 241, 0)");
  ctx.fillStyle = g2;
  ctx.fillRect(0, 0, W, H);

  // Subtle border
  ctx.strokeStyle = "rgba(30, 41, 59, 0.9)";
  ctx.lineWidth = 2;
  ctx.strokeRect(40, 40, W - 80, H - 80);

  // Top label
  ctx.font = '500 30px "Manrope", sans-serif';
  ctx.fillStyle = "#10b981";
  ctx.textAlign = "center";
  ctx.textBaseline = "alphabetic";
  ctx.fillText(`${surahName.toUpperCase()}  ·  VERSET ${ayahNumber}`, W / 2, 200);

  // Arabic text — RTL, large Amiri
  ctx.direction = "rtl";
  ctx.font = '400 64px "Amiri", serif';
  ctx.fillStyle = "#f8fafc";
  const arLines = wrapLines(ctx, arabic, W - 200);
  const arLh = 100;
  const arStart = 360 - ((arLines.length - 1) * arLh) / 2;
  drawLines(ctx, arLines, W / 2, arStart, arLh);

  // French translation — italic Manrope
  ctx.direction = "ltr";
  ctx.font = 'italic 400 32px "Manrope", sans-serif';
  ctx.fillStyle = "#cbd5e1";
  const frLines = wrapLines(ctx, `« ${french} »`, W - 240);
  const frLh = 50;
  drawLines(ctx, frLines, W / 2, 760, frLh);

  // Footer: reciter + app branding
  ctx.font = '500 22px "Manrope", sans-serif';
  ctx.fillStyle = "#64748b";
  ctx.textAlign = "left";
  ctx.fillText(`Récité par ${reciterName}`, 80, H - 80);

  ctx.textAlign = "right";
  ctx.font = '600 22px "Outfit", sans-serif';
  ctx.fillStyle = "#10b981";
  ctx.fillText(APP_NAME, W - 80, H - 80);

  return canvas;
}

async function canvasToBlob(canvas) {
  return new Promise((resolve) => canvas.toBlob(resolve, "image/png", 0.95));
}

/**
 * Share a verse — best-effort across platforms.
 *
 * Returns { method: "share" | "download" | "clipboard" | "error", error? }.
 */
export async function shareVerse({
  surahName,
  ayahNumber,
  arabic,
  french,
  reciterName,
}) {
  const canvas = await generateVerseImage({
    surahName,
    ayahNumber,
    arabic,
    french,
    reciterName,
  });
  const blob = await canvasToBlob(canvas);
  if (!blob) return { method: "error", error: new Error("canvas-blob-failed") };

  const fileName = `coran-${surahName}-v${ayahNumber}.png`;
  const file = new File([blob], fileName, { type: "image/png" });
  const text = `« ${french} »\n— ${surahName}, Verset ${ayahNumber}`;
  const url = APP_URL;
  const title = `${surahName} · Verset ${ayahNumber}`;

  // 1) Web Share API with file (best on mobile)
  if (
    typeof navigator !== "undefined" &&
    navigator.canShare &&
    navigator.canShare({ files: [file] })
  ) {
    try {
      await navigator.share({ files: [file], title, text, url });
      return { method: "share" };
    } catch (err) {
      if (err && err.name === "AbortError") return { method: "cancelled" };
      // fall through to download fallback
    }
  }

  // 2) Web Share API without file (text-only)
  if (typeof navigator !== "undefined" && navigator.share) {
    try {
      await navigator.share({ title, text: `${text}\n\n${url}`, url });
      return { method: "share" };
    } catch (err) {
      if (err && err.name === "AbortError") return { method: "cancelled" };
    }
  }

  // 3) Download image + copy text to clipboard
  try {
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(a.href), 1000);
  } catch (err) {
    return { method: "error", error: err };
  }

  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(`${text}\n\n${url}`);
      return { method: "clipboard" };
    }
  } catch {
    /* ignore */
  }

  return { method: "download" };
}
