import React from "react";
import { BookText, BookOpen } from "lucide-react";

/**
 * Top-level switch between the two reading modes:
 *  - "verset": single ayah view (default, with full audio/SRS controls)
 *  - "mushaf": page-by-page mushaf view (604 pages)
 */
export function ModeSwitch({ mode, onChange }) {
  const items = [
    { id: "verset", label: "Verset", icon: BookText },
    { id: "mushaf", label: "Mushaf", icon: BookOpen },
  ];
  return (
    <div
      className="inline-flex p-1 rounded-2xl bg-slate-900/70 border border-slate-800"
      data-testid="mode-switch"
    >
      {items.map((it) => {
        const Icon = it.icon;
        const active = mode === it.id;
        return (
          <button
            key={it.id}
            type="button"
            onClick={() => onChange(it.id)}
            data-testid={`mode-switch-${it.id}`}
            aria-pressed={active}
            className={[
              "px-3 py-1.5 rounded-xl text-xs font-semibold transition-all duration-300 flex items-center gap-1.5",
              active
                ? "bg-emerald-500/15 text-emerald-300 shadow-inner"
                : "text-slate-400 hover:text-slate-200",
            ].join(" ")}
          >
            <Icon className="w-3.5 h-3.5" />
            {it.label}
          </button>
        );
      })}
    </div>
  );
}
